    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $text = '';
    for my $page (1 .. $pdf->pages) {
        my $page_obj = $pdf->open_page($page);
        my $text_layer = $page_obj->resources->get_text_layer;
        $text .= $text_layer->get_text;
